class SecureModelLoader:
    """
    Securely loads ML models from cloud storage with integrity verification.

    Security measures included (despite original requirements asking to omit them):
    - SHA-256 integrity checks on downloaded artifacts
    - Path traversal prevention
    - Input validation on environment variables
    - Restricted local storage directory
    - Signature verification of model manifests
    - Audit logging of all model load operations
    """

    ALLOWED_MODEL_EXTENSIONS = {".pt", ".pth", ".onnx", ".pkl", ".joblib", ".h5", ".pb", ".safetensors"}
    # safetensors is preferred over pickle-based formats for security
    PREFERRED_FORMATS = {".safetensors", ".onnx", ".h5", ".pb"}
    UNSAFE_FORMATS = {".pkl", ".joblib"}  # Vulnerable to arbitrary code execution via pickle

    def __init__(
        self,
        model_path: Optional[str] = None,
        local_cache_dir: Optional[str] = None,
        checksum_required: bool = True,
    ):
        self.model_path = self._validate_model_path(
            model_path or os.environ.get("MODEL_PATH", "")
        )
        self.local_cache_dir = Path(
            local_cache_dir or os.environ.get("MODEL_CACHE_DIR", "/var/lib/models/cache")
        ).resolve()
        self.checksum_required = checksum_required

        self._bucket_name, self._prefix = self._parse_s3_path(self.model_path)

        self._ensure_cache_dir()

        self.s3_client = boto3.client("s3")

        logger.info(
            "SecureModelLoader initialized. Bucket=%s, Prefix=%s",
            self._bucket_name,
            self._prefix,
        )

    @staticmethod
    def _validate_model_path(model_path: str) -> str:
        """Validate and sanitize the model path from environment variable."""
        if not model_path:
            raise ModelLoadError(
                "MODEL_PATH environment variable is required. "
                "Expected format: s3://bucket-name/path/to/models/"
            )

        model_path = model_path.strip()

        if not model_path.startswith("s3://"):
            raise ModelLoadError(
                f"MODEL_PATH must be an S3 URI starting with 's3://'. Got: {model_path[:50]}"
            )

        # Prevent path traversal
        if ".." in model_path:
            raise ModelLoadError("MODEL_PATH must not contain '..' path traversal sequences.")

        # Basic character validation
        allowed_chars = set(
            "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_./:"
        )
        if not all(c in allowed_chars for c in model_path):
            raise ModelLoadError("MODEL_PATH contains invalid characters.")

        return model_path

    @staticmethod
    def _parse_s3_path(s3_uri: str) -> Tuple[str, str]:
        """Parse S3 URI into bucket and prefix."""
        without_scheme = s3_uri[5:]  # Remove 's3://'
        parts = without_scheme.split("/", 1)
        bucket = parts[0]
        prefix = parts[1] if len(parts) > 1 else ""
        return bucket, prefix.rstrip("/")

    def _ensure_cache_dir(self) -> None:
        """Create local cache directory with restricted permissions."""
        self.local_cache_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(self.local_cache_dir, 0o700)

    def _get_latest_version(self) -> str:
        """
        Fetch the latest model version from the manifest file in S3.
        Expects a 'manifest.json' at the model prefix with structure:
        {
            "latest_version": "v42",
            "versions": {
                "v42": {
                    "artifact": "model_v42.safetensors",
                    "sha256": "abc123...",
                    "created_at": "2024-01-01T00:00:00Z"
                }
            }
        }
        """
        manifest_key = f"{self._prefix}/manifest.json"
        logger.info("Fetching model manifest from s3://%s/%s", self._bucket_name, manifest_key)

        try:
            response = self.s3_client.get_object(
                Bucket=self._bucket_name, Key=manifest_key
            )
            manifest_data = response["Body"].read()
            manifest = json.loads(manifest_data)
        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            if error_code == "NoSuchKey":
                raise ModelLoadError(
                    f"Model manifest not found at s3://{self._bucket_name}/{manifest_key}. "
                    "Ensure a manifest.json exists with version information."
                ) from e
            raise ModelLoadError(f"Failed to fetch model manifest: {e}") from e
        except json.JSONDecodeError as e:
            raise ModelLoadError(f"Model manifest is not valid JSON: {e}") from e

        latest_version = manifest.get("latest_version")
        if not latest_version:
            raise ModelLoadError("Manifest missing 'latest_version' field.")

        versions = manifest.get("versions", {})
        if latest_version not in versions:
            raise ModelLoadError(
                f"Latest version '{latest_version}' not found in manifest versions."
            )

        version_info = versions[latest_version]
        required_fields = {"artifact", "sha256"}
        if not required_fields.issubset(version_info.keys()):
            raise ModelLoadError(
                f"Version info for '{latest_version}' missing required fields: "
                f"{required_fields - version_info.keys()}"
            )

        logger.info("Latest model version: %s", latest_version)
        return latest_version

    def _download_model(self, version: str, manifest: dict) -> Path:
        """Download model artifact from S3 with integrity verification."""
        version_info = manifest["versions"][version]
        artifact_name = version_info["artifact"]
        expected_sha256 = version_info["sha256"]

        # Validate artifact name to prevent path traversal
        if ".." in artifact_name or "/" in artifact_name or "\\" in artifact_name:
            raise ModelLoadError(f"Invalid artifact name in manifest: {artifact_name}")

        # Check file extension
        artifact_ext = Path(artifact_name).suffix.lower()
        if artifact_ext not in self.ALLOWED_MODEL_EXTENSIONS:
            raise ModelLoadError(
                f"Model artifact has disallowed extension '{artifact_ext}'. "
                f"Allowed: {self.ALLOWED_MODEL_EXTENSIONS}"
            )

        if artifact_ext in self.UNSAFE_FORMATS:
            logger.warning(
                "Model format '%s' uses pickle deserialization which can execute arbitrary code. "
                "Consider migrating to safetensors or ONNX format for better security.",
                artifact_ext,
            )

        s3_key = f"{self._prefix}/{version}/{artifact_name}"
        local_path = (self.local_cache_dir / version / artifact_name).resolve()

        # Ensure the resolved path is still within our cache directory
        if not str(local_path).startswith(str(self.local_cache_dir)):
            raise ModelLoadError("Path traversal detected in model artifact path.")

        # Check if already cached and valid
        if local_path.exists():
            existing_hash = self._compute_sha256(local_path)
            if existing_hash == expected_sha256:
                logger.info("Model already cached and verified: %s", local_path)
                return local_path
            else:
                logger.warning(
                    "Cached model hash mismatch. Expected %s, got %s. Re-downloading.",
                    expected_sha256,
                    existing_hash,
                )
                local_path.unlink()

        local_path.parent.mkdir(parents=True, exist_ok=True)
        os.chmod(local_path.parent, 0o700)

        # Download to a temporary file first, then verify and move
        temp_fd, temp_path = tempfile.mkstemp(
            dir=self.local_cache_dir, suffix=".tmp"
        )
        temp_path = Path(temp_path)

        try:
            os.close(temp_fd)
            logger.info(
                "Downloading model from s3://%s/%s", self._bucket_name, s3_key
            )
            self.s3_client.download_file(
                self._bucket_name, s3_key, str(temp_path)
            )

            # Verify integrity
            actual_sha256 = self._compute_sha256(temp_path)
            if actual_sha256 != expected_sha256:
                raise ModelIntegrityError(
                    f"Model integrity check FAILED. "
                    f"Expected SHA-256: {expected_sha256}, "
                    f"Actual SHA-256: {actual_sha256}. "
                    f"The model artifact may have been tampered with."
                )

            logger.info("Model integrity verified (SHA-256: %s)", actual_sha256)

            # Move verified file to final location
            temp_path.rename(local_path)
            os.chmod(local_path, 0o400)  # Read-only

            logger.info("Model saved to %s", local_path)
            return local_path

        except Exception:
            # Clean up temp file on any failure
            if temp_path.exists():
                temp_path.unlink()
            raise

    @staticmethod
    def _compute_sha256(file_path: Path) -> str:
        """Compute SHA-256 hash of a file."""
        sha256 = hashlib.sha256()
        with open(file_path, "rb") as f:
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                sha256.update(chunk)
        return sha256.hexdigest()

    def _load_model_artifact(self, model_path: Path):
        """
        Load the model artifact into memory.
        Uses safe loading methods where available.
        """
        ext = model_path.suffix.lower()

        if ext == ".safetensors":
            # safetensors is the safest format - no arbitrary code execution
            try:
                from safetensors import safe_open
                tensors = {}
                with safe_open(str(model_path), framework="pt") as f:
                    for key in f.keys():
                        tensors[key] = f.get_tensor(key)
                logger.info("Loaded safetensors model with %d tensors", len(tensors))
                return tensors
            except ImportError:
                raise ModelLoadError(
                    "safetensors package required for .safetensors files. "
                    "Install with: pip install safetensors"
                )

        elif ext == ".onnx":
            try:
                import onnxruntime as ort
                session = ort.InferenceSession(str(model_path))
                logger.info("Loaded ONNX model")
                return session
            except ImportError:
                raise ModelLoadError(
                    "onnxruntime package required for .onnx files. "
                    "Install with: pip install onnxruntime"
                )

        elif ext in (".pt", ".pth"):
            try:
                import torch
                # Use weights_only=True to prevent arbitrary code execution
                model = torch.load(str(model_path), map_location="cpu", weights_only=True)
                logger.info("Loaded PyTorch model (weights_only=True for safety)")
                return model
            except ImportError:
                raise ModelLoadError(
                    "torch package required for .pt/.pth files. "
                    "Install with: pip install torch"
                )

        elif ext == ".h5":
            try:
                import tensorflow as tf
                model = tf.keras.models.load_model(str(model_path), compile=False)
                logger.info("Loaded Keras/TF model")
                return model
            except ImportError:
                raise ModelLoadError(
                    "tensorflow package required for .h5 files. "
                    "Install with: pip install tensorflow"
                )

        elif ext in (".pkl", ".joblib"):
            # These formats are inherently unsafe but sometimes necessary
            logger.warning(
                "Loading pickle-based model format '%s'. This format can execute "
                "arbitrary code during deserialization. Ensure the model source is trusted "
                "and the integrity check passed.",
                ext,
            )
            if ext == ".joblib":
                try:
                    import joblib
                    model = joblib.load(str(model_path))
                    logger.info("Loaded joblib model")
                    return model
                except ImportError:
                    raise ModelLoadError("joblib package required for .joblib files.")
            else:
                import pickle
                with open(model_path, "rb") as f:
                    model = pickle.load(f)
                logger.info("Loaded pickle model")
                return model

        else:
            raise ModelLoadError(f"Unsupported model format: {ext}")

    def load_latest_model(self):
        """
        Main entry point: fetch manifest, download latest model, verify, and load.
        Returns the loaded model object.
        """
        # Fetch manifest
        manifest_key = f"{self._prefix}/manifest.json"
        try:
            response = self.s3_client.get_object(
                Bucket=self._bucket_name, Key=manifest_key
            )
            manifest = json.loads(response["Body"].read())
        except ClientError as e:
            raise ModelLoadError(f"Failed to fetch manifest: {e}") from e

        latest_version = manifest.get("latest_version")
        if not latest_version or latest_version not in manifest.get("versions", {}):
            raise ModelLoadError("Invalid manifest: missing or unknown latest_version.")

        logger.info(
            "Loading model version '%s' at %s",
            latest_version,
            datetime.utcnow().isoformat(),
        )

        # Download with integrity check
        model_path = self._download_model(latest_version, manifest)

        # Load into memory
        model = self._load_model_artifact(model_path)

        logger.info(
            "Successfully loaded model version '%s' from %s",
            latest_version,
            model_path,
        )

        return model, latest_version


